from llama_index.core.workflow import Workflow, StartEvent, StopEvent
from typing import List

class CoordinationChecker:
    def __init__(self):
        self.agent_responses = []

    def check_drift(self, responses: List[str]) -> bool:
        if len(responses) < 2:
            return True

        # Semantic similarity check
        from llama_index.llms.openai import OpenAI
        llm = OpenAI(model='gpt-3.5-turbo')

        drift_prompt = f"""Compare these agent responses for coordination failure:
        Agent1: {responses[0]}
        Agent2: {responses[1]}
        Do they cover the same core information? Yes/No"""

        result = llm.complete(drift_prompt)
        return 'Yes' in str(result)

