def validate_tool_sequence(tool_calls: list) -> dict:
    coordination_score = 0
    issues = []

    for i, call in enumerate(tool_calls):
        tool_name = call.get('name', '')
        args = call.get('args', {})

        if i > 0:
            prev_tool = tool_calls[i-1]['name']
            # Check if current tool logically follows previous
            if not is_logical_succession(prev_tool, tool_name):
                issues.append(f'Tool {i}: {tool_name} doesn\'t follow {prev_tool}')
                coordination_score -= 1

    return {
        'coordination_score': coordination_score,
        'issues': issues,
        'healthy': coordination_score >= -1
    }

def is_logical_succession(prev: str, current: str) -> bool:
    succession_map = {
        'research_retrieve': ['analyze_data', 'summarize'],
        'data_retrieve': ['chart_create', 'analyze_trends']
    }
    return current in succession_map.get(prev, [])

