from functools import wraps
import asyncio

class CoordinationRetryHandler(LlamaDebugHandler):
    def __init__(self, max_retries=3):
        super().__init__()
        self.max_retries = max_retries
        self.context_chain = []

    def retry_with_full_context(func):
        @wraps(func)
        async def wrapper(*args, **kwargs):
            for attempt in range(3):
                try:
                    result = await func(*args, **kwargs)
                    handler.context_chain.append(str(result))
                    return result
                except Exception as e:
                    if attempt == 2:
                        raise
                    # Retry with accumulated context
                    kwargs['context'] = '\n'.join(handler.context_chain)
                    await asyncio.sleep(0.1)
            return result
        return wrapper

# Apply to all agent query engines
@CoordinationRetryHandler.retry_with_full_context
async def coordinated_query(engine, query, context=None):
    if context:
        query = f"Previous context: {context}\n\nCurrent query: {query}"
    return await engine.aquery(query)

